section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/release-qa-cycle-template.json",
  "type": "object",
  "title": "Release QA Cycle Template",
  "required": [
    "cycle_id",
    "release_id",
    "stages",
    "decision",
    "approver",
    "retro_note",
    "recorded_at"
  ],
  "additionalProperties": false,
  "properties": {
    "cycle_id": {
      "type": "string",
      "minLength": 1,
      "description": "Cycle identifier."
    },
    "release_id": {
      "type": "string",
      "minLength": 1,
      "description": "Linked release id."
    },
    "stages": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "Exactly 6 items: {id, owner, outcome \u2208 [pass, fail, blocked, waived], waiver_reason \u2208 string|null, artefact_link}."
    },
    "decision": {
      "type": "string",
      "enum": [
        "go",
        "no_go"
      ],
      "description": "Final cycle decision."
    },
    "approver": {
      "type": "string",
      "minLength": 1,
      "description": "Single decision approver handle."
    },
    "retro_note": {
      "type": "string",
      "minLength": 1,
      "description": "Keep/change short note."
    },
    "recorded_at": {
      "type": "string",
      "minLength": 1,
      "description": "ISO timestamp."
    }
  }
}
